public boolean xyBalance(String str) {
    int lastYIndex = str.length();
    for (int i = 0; i < str.length(); i++) {
        char c = str.charAt(i);
        if (c == 'x') {
            lastYIndex = Math.min(lastYIndex, str.lastIndexOf('y', i));
        }
    }
    return lastYIndex != str.length();
}

