public int makeChocolate(int small, int big, int goal) {
    int bigWeight = big * 5;
    int remainingWeight = goal - bigWeight;
    if (remainingWeight > small) {
        return -1;
    } else {
        return remainingWeight;
    }
}

public int[] tenRun(int[] nums) {
    if(nums == null || nums.length == 0){
        return nums;
    }

    int n = nums.length;
    for(int i = 0; i < n; i++){
        if(nums[i] % 10 == 0){
            int value = nums[i];
            for(int j = i + 1; j < n; j++){
                if(nums[j] % 10 == 0){
                    break;
                }
                nums[j] = value;
            }
        }
    }
    return nums;
}

