public int[] frontPiece(int[] nums) {
    int[] front = new int[2];
    int length = Math.min(nums.length, 2);
    for (int i = 0; i < length; i++) {
        front[i] = nums[i];
    }
    return front;
}

public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

